/* DataDrivenChemistryPapers — client-side search, authors and journals pages.
 * Vanilla JS, no dependencies. Loads the per-year JSON shards generated by
 * the Python pipeline and filters them in the browser.
 *
 * Loading is progressive: the newest few years render immediately, older
 * shards stream in the background and the page updates when complete — so
 * the UI stays instant even with tens of thousands of indexed papers. */
(function () {
  "use strict";

  var app = document.getElementById("app");
  if (!app) return;
  var PAGE = app.dataset.page;
  var ROOT = app.dataset.root || "";
  var PAGE_SIZE = 100;
  var INITIAL_YEARS = 3; // shards loaded before first render

  // ---------------------------------------------------------------- utils
  function esc(s) {
    return String(s == null ? "" : s).replace(/[&<>"']/g, function (c) {
      return { "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;" }[c];
    });
  }
  function params() { return new URLSearchParams(location.search); }
  function prettyDate(iso) {
    if (!iso) return "";
    var m = ["January","February","March","April","May","June","July",
             "August","September","October","November","December"];
    var p = iso.split("-");
    if (p.length >= 3) return (+p[2]) + " " + m[+p[1] - 1] + " " + p[0];
    if (p.length === 2) return m[+p[1] - 1] + " " + p[0];
    return iso;
  }
  function scoreClass(s) { return s >= 90 ? "score-high" : s >= 70 ? "score-mid" : "score-low"; }
  function byDateDesc(a, b) {
    return (b.published || "").localeCompare(a.published || "");
  }

  function renderCard(p) {
    var authors = p.authors.slice(0, 12).map(function (a) {
      return '<a href="' + ROOT + 'authors.html?a=' + encodeURIComponent(a) + '">' + esc(a) + "</a>";
    }).join(", ");
    if (p.authors.length > 12) authors += " and " + (p.authors.length - 12) + " more";
    var chips = "";
    (p.categories || []).slice(0, 5).forEach(function (c) {
      chips += '<a class="chip chip-cat" href="' + ROOT + 'search.html?category=' +
        encodeURIComponent(c) + '">' + esc(c) + "</a>";
    });
    (p.tags || []).slice(0, 6).forEach(function (t) {
      if ((p.categories || []).indexOf(t) === -1)
        chips += '<a class="chip" href="' + ROOT + 'search.html?q=' +
          encodeURIComponent(t) + '">' + esc(t) + "</a>";
    });
    var link = p.url || (p.doi ? "https://doi.org/" + p.doi : "");
    var orig = link ? '<a class="btn btn-primary" href="' + esc(link) +
      '" target="_blank" rel="noopener">Original paper ↗</a>' : "";
    var journal = p.journal
      ? '<a class="meta-journal" href="' + ROOT + 'journals.html?j=' +
        encodeURIComponent(p.journal) + '">' + esc(p.journal) + "</a> · " : "";
    return '<article class="card">' +
      '<h3 class="card-title"><a href="' + esc(p.url || ("https://doi.org/" + p.doi)) +
      '" target="_blank" rel="noopener">' + esc(p.title) + "</a></h3>" +
      '<p class="card-authors">' + authors + "</p>" +
      '<p class="card-meta">' + journal +
      "<time>" + esc(prettyDate(p.published)) + "</time> · " +
      '<span class="meta-source">' + esc(p.source) + "</span>" +
      '<span class="score ' + scoreClass(p.score) + '" title="Relevance score">' +
      p.score + "</span></p>" +
      '<p class="card-chips">' + chips + "</p>" +
      '<p class="card-actions">' + orig + "</p></article>";
  }

  // ---------------------------------------------------------------- data
  function fetchShard(file) {
    return fetch(ROOT + "assets/data/" + file).then(function (r) {
      return r.ok ? r.json() : [];
    });
  }

  /* Calls onData(papers, complete) once with the newest years, then again
   * with the full archive. */
  function loadProgressive(onData) {
    return fetch(ROOT + "assets/data/manifest.json")
      .then(function (r) {
        if (!r.ok) throw new Error("manifest missing");
        return r.json();
      })
      .then(function (manifest) {
        var years = (manifest.years || []).slice()
          .sort(function (a, b) { return b.year - a.year; });
        var first = years.slice(0, INITIAL_YEARS);
        var rest = years.slice(INITIAL_YEARS);
        return Promise.all(first.map(function (y) { return fetchShard(y.file); }))
          .then(function (shards) {
            var recent = [].concat.apply([], shards).sort(byDateDesc);
            onData(recent, rest.length === 0);
            if (!rest.length) return;
            return Promise.all(rest.map(function (y) { return fetchShard(y.file); }))
              .then(function (older) {
                var all = recent.concat([].concat.apply([], older)).sort(byDateDesc);
                onData(all, true);
              });
          });
      });
  }

  // ---------------------------------------------------------------- search page
  function searchPage() {
    var q = params();
    var papers = [];
    var complete = false;
    var built = false;
    var shown = PAGE_SIZE;

    function build() {
      app.innerHTML =
        '<h1>Search</h1>' +
        '<div class="filter-bar">' +
        '<input type="search" id="f-q" placeholder="Search titles, authors, journals, universities, methods…" value="' +
        esc(q.get("q") || q.get("author") || "") + '">' +
        '<select id="f-year"><option value="">All years</option></select>' +
        '<select id="f-category"><option value="">All categories</option></select>' +
        '<select id="f-journal"><option value="">All journals</option></select>' +
        '<select id="f-source"><option value="">All sources</option></select>' +
        '<select id="f-score"><option value="">Any relevance</option>' +
        '<option value="90">≥ 90 — extremely relevant</option>' +
        '<option value="70">≥ 70 — very relevant</option>' +
        '<option value="50">≥ 50 — relevant</option></select>' +
        '<select id="f-sort"><option value="date">Newest first</option>' +
        '<option value="score">Relevance score</option></select>' +
        "</div>" +
        '<p class="result-meta"><span id="result-count"></span>' +
        '<span id="load-state" class="load-state"></span>' +
        '<a class="clear-filters" href="' + ROOT + 'search.html">Clear filters</a></p>' +
        '<div id="results"></div><p class="more" id="more-wrap"></p>';

      var timer;
      document.getElementById("f-q").addEventListener("input", function () {
        clearTimeout(timer); shown = PAGE_SIZE;
        timer = setTimeout(apply, 150);
      });
      ["f-year", "f-category", "f-journal", "f-source", "f-score", "f-sort"]
        .forEach(function (id) {
          document.getElementById(id).addEventListener("change", function () {
            shown = PAGE_SIZE; apply();
          });
        });
    }

    function refreshOptions() {
      fillOptions("f-year", uniq(papers.map(function (p) {
        return String((p.published || "").slice(0, 4));
      })).sort().reverse(), q.get("year"));
      fillOptions("f-category", uniqCount(papers, "categories").sort(function (a, b) {
        return a.localeCompare(b);
      }), q.get("category"));
      fillOptions("f-journal", uniqCount(papers, "journal"), q.get("journal"));
      fillOptions("f-source", uniq(papers.map(function (p) { return p.source; })).sort(),
                  q.get("source"));
      setSelect("f-score", q.get("minscore"));
    }

    function apply() {
      var query = val("f-q").toLowerCase().trim();
      var terms = query ? query.split(/\s+/) : [];
      var year = val("f-year"), cat = val("f-category"),
          journal = val("f-journal"), source = val("f-source"),
          minScore = +val("f-score") || 0, sort = val("f-sort");
      var out = papers.filter(function (p) {
        if (year && (p.published || "").slice(0, 4) !== year) return false;
        if (cat && (p.categories || []).indexOf(cat) === -1) return false;
        if (journal && p.journal !== journal) return false;
        if (source && p.source !== source) return false;
        if (p.score < minScore) return false;
        if (terms.length) {
          var hay = (p.title + " " + p.authors.join(" ") + " " + p.journal + " " +
            (p.publisher || "") + " " + p.doi + " " + (p.categories || []).join(" ") + " " +
            (p.tags || []).join(" ") + " " + (p.affiliations || []).join(" ") + " " +
            (p.published || "")).toLowerCase();
          for (var i = 0; i < terms.length; i++)
            if (hay.indexOf(terms[i]) === -1) return false;
        }
        return true;
      });
      if (sort === "score") out.sort(function (a, b) { return b.score - a.score; });
      document.getElementById("result-count").textContent =
        out.length.toLocaleString() + " paper" + (out.length === 1 ? "" : "s");
      document.getElementById("load-state").textContent =
        complete ? "" : "loading full archive…";
      document.getElementById("results").innerHTML =
        out.slice(0, shown).map(renderCard).join("") ||
        '<p class="empty">No papers match these filters.</p>';
      var moreWrap = document.getElementById("more-wrap");
      moreWrap.innerHTML = out.length > shown
        ? '<button class="btn" id="more-btn">Show more (' + (out.length - shown) + " remaining)</button>"
        : "";
      var btn = document.getElementById("more-btn");
      if (btn) btn.onclick = function () { shown += PAGE_SIZE; apply(); };
    }

    return function onData(newPapers, isComplete) {
      papers = newPapers;
      complete = isComplete;
      if (!built) { build(); built = true; }
      refreshOptions();
      apply();
    };
  }

  function val(id) { return document.getElementById(id).value; }
  function uniq(arr) {
    return arr.filter(function (v, i) { return v && arr.indexOf(v) === i; });
  }
  function uniqCount(papers, key) {
    var counts = {};
    papers.forEach(function (p) {
      var vals = key === "categories" ? (p.categories || []) : [p[key]];
      vals.forEach(function (v) { if (v) counts[v] = (counts[v] || 0) + 1; });
    });
    return Object.keys(counts).sort(function (a, b) { return counts[b] - counts[a]; });
  }
  function fillOptions(id, values, urlValue) {
    var select = document.getElementById(id);
    var current = select.value || urlValue || "";
    while (select.options.length > 1) select.remove(1);
    values.forEach(function (v) {
      var opt = document.createElement("option");
      opt.value = v; opt.textContent = v;
      select.appendChild(opt);
    });
    setSelect(id, current);
  }
  function setSelect(id, value) {
    if (!value) return;
    var select = document.getElementById(id);
    for (var i = 0; i < select.options.length; i++)
      if (select.options[i].value === value) { select.value = value; return; }
  }

  // ------------------------------------------------- directory pages
  function directoryPage(kind) {
    var isAuthor = kind === "authors";
    var q = params();
    var selected = q.get(isAuthor ? "a" : "j");
    if (selected) return detailPage(kind, selected);

    var title = isAuthor ? "Authors" : "Journals";
    var papers = [];
    var complete = false;
    var built = false;
    var counts = {}, names = [];

    function build() {
      app.innerHTML = "<h1>" + title + "</h1>" +
        '<div class="filter-bar">' +
        '<input type="search" id="dir-q" placeholder="Filter ' +
        title.toLowerCase() + '…">' +
        '<select id="dir-cat"><option value="">All categories</option></select>' +
        "</div>" +
        '<p class="result-meta"><span id="result-count"></span>' +
        '<span id="load-state" class="load-state"></span></p>' +
        '<ul class="dir-list" id="dir-list"></ul>';
      document.getElementById("dir-q").addEventListener("input", render);
      document.getElementById("dir-cat").addEventListener("change", function () {
        recount(); render();
      });
    }

    function recount() {
      var cat = val("dir-cat");
      counts = {};
      papers.forEach(function (p) {
        if (cat && (p.categories || []).indexOf(cat) === -1) return;
        var ns = isAuthor ? p.authors : (p.journal ? [p.journal] : []);
        ns.forEach(function (n) { counts[n] = (counts[n] || 0) + 1; });
      });
      names = Object.keys(counts).sort(function (a, b) {
        return counts[b] - counts[a] || a.localeCompare(b);
      });
    }

    function render() {
      var needle = val("dir-q").toLowerCase().trim();
      var cat = val("dir-cat");
      var catParam = cat ? "&cat=" + encodeURIComponent(cat) : "";
      var out = needle
        ? names.filter(function (n) { return n.toLowerCase().indexOf(needle) !== -1; })
        : names;
      document.getElementById("result-count").textContent =
        out.length.toLocaleString() + " " + title.toLowerCase() +
        (cat ? " in " + cat : "");
      document.getElementById("load-state").textContent =
        complete ? "" : "loading full archive…";
      document.getElementById("dir-list").innerHTML =
        out.slice(0, 1500).map(function (n) {
          return '<li><a href="?' + (isAuthor ? "a" : "j") + "=" +
            encodeURIComponent(n) + catParam + '">' + esc(n) + '</a>' +
            '<span class="count">' + counts[n] + "</span></li>";
        }).join("") +
        (out.length > 1500
          ? '<li class="empty">…and ' + (out.length - 1500).toLocaleString() +
            " more — type above to narrow down.</li>" : "");
    }

    return function onData(newPapers, isComplete) {
      papers = newPapers;
      complete = isComplete;
      if (!built) { build(); built = true; }
      fillOptions("dir-cat", uniqCount(papers, "categories").sort(function (a, b) {
        return a.localeCompare(b);
      }), q.get("cat"));
      recount();
      render();
    };
  }

  function detailPage(kind, name) {
    var isAuthor = kind === "authors";
    var cat = params().get("cat");
    var baseName = isAuthor ? "authors" : "journals";
    return function onData(papers, complete) {
      var all = papers.filter(function (p) {
        return isAuthor ? p.authors.indexOf(name) !== -1 : p.journal === name;
      });
      var matches = cat
        ? all.filter(function (p) { return (p.categories || []).indexOf(cat) !== -1; })
        : all;
      document.title = name + " · DataDrivenChemistryPapers";
      var meta = matches.length.toLocaleString() +
        " paper" + (matches.length === 1 ? "" : "s") +
        (cat ? " in " + esc(cat) : "") +
        (complete ? "" : " so far — loading full archive…");
      var showAll = (cat && all.length > matches.length)
        ? ' · <a href="?' + (isAuthor ? "a" : "j") + "=" + encodeURIComponent(name) +
          '">show all ' + all.length.toLocaleString() + " papers</a>"
        : "";
      app.innerHTML = "<h1>" + esc(name) + "</h1>" +
        '<p class="result-meta"><span>' + meta + showAll + "</span>" +
        '<a href="' + ROOT + baseName + ".html" +
        (cat ? "?cat=" + encodeURIComponent(cat) : "") + '">← All ' +
        baseName + "</a></p>" +
        '<div id="results">' + matches.map(renderCard).join("") + "</div>";
    };
  }

  // ---------------------------------------------------------------- boot
  var handler = null;
  if (PAGE === "search") handler = searchPage();
  else if (PAGE === "authors") handler = directoryPage("authors");
  else if (PAGE === "journals") handler = directoryPage("journals");
  if (!handler) return;

  loadProgressive(handler).catch(function (err) {
    app.innerHTML = '<p class="empty">Could not load the paper index (' +
      esc(err.message) + "). If you opened this page from the local filesystem, " +
      "serve it over HTTP instead (e.g. <code>python -m http.server</code>).</p>";
  });
})();
